#!/bin/bash -l
#
# Submit CANDEL inference tasks. Cluster (arc or glamdring) is picked up
# from `machine` in local_config.toml via _submit_lib.sh.
#
# Task files are generated by generate_tasks.py and have the format:
#   <index> <config_path>

set -euo pipefail

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../.." && pwd)"
# shellcheck source=../_submit_lib.sh
source "$ROOT/scripts/_submit_lib.sh"

queue=""
ncpu=1
memory=16
gputype=""
gpu_mem=""
local_mode=false
dry=false

usage() {
    cat <<EOF
usage: $(basename "$0") -q QUEUE [-n NCPU] [-m MEMORY] [--gputype TYPE]
                        [--local] [--dry] <task_index>

Submit CANDEL inference tasks.

positional:
  task_index              reads tasks_<index>.txt. Suffix 'X' matches
                          tasks_<base>X*.txt (split mode).

options:
  -q, --queue QUEUE       queue/partition (REQUIRED unless --local)
                            glamdring CPU: redwood, berg, cmb
                            glamdring GPU: gpulong, cmbgpu, optgpu
                            arc: short, medium, long
  -n, --ncpu NCPU         number of CPUs (default: $ncpu)
  -m, --memory MEMORY     memory per job (GB, default: $memory)
  --gputype TYPE          GPU type (e.g. h100, l40s)
  --gpu-mem GB            Min GPU VRAM in GB (arc only; queries sinfo)
  --local                 run on login node
  --dry                   print submit commands without submitting
EOF
    exit 0
}

task_index=""
while [[ $# -gt 0 ]]; do
    case "$1" in
        -h|--help)       usage ;;
        -q|--queue)      queue="$2"; shift 2 ;;
        -n|--ncpu)       ncpu="$2"; shift 2 ;;
        -m|--memory)     memory="$2"; shift 2 ;;
        --gputype)       gputype="$2"; shift 2 ;;
        --gpu-mem)       gpu_mem="$2"; shift 2 ;;
        --local)         local_mode=true; shift ;;
        --dry)           dry=true; shift ;;
        *)               task_index="$1"; shift ;;
    esac
done

if [[ -z "$task_index" ]]; then
    echo "[ERROR] Missing task_index"; exit 1
fi
if ! $local_mode && [[ -z "$queue" ]]; then
    echo "[ERROR] -q QUEUE is required (cluster=$CANDEL_CLUSTER)"; exit 1
fi

# GPU queues per cluster.
is_gpu=false
case "$CANDEL_CLUSTER:$queue" in
    glamdring:gpulong|glamdring:cmbgpu|glamdring:optgpu) is_gpu=true ;;
    arc:*)
        # On arc any queue can request a GPU; treat --gputype presence
        # as opt-out (arc doesn't honour glamdring gputypes). GPU use on
        # arc here is implicit by --gputype being ignored; to actually
        # request a GPU on arc, keep old semantics: if gputype provided
        # OR queue name implies GPU, assume GPU. Simpler: only GPU when
        # the user explicitly gave --gputype.
        [[ -n "$gputype" || -n "$gpu_mem" ]] && is_gpu=true
        ;;
esac


# Resolve task files.
task_files=()
if [[ "$task_index" == *X ]]; then
    while IFS= read -r f; do task_files+=("$f"); done \
        < <(compgen -G "tasks_${task_index}*.txt" | sort -V)
    if (( ${#task_files[@]} == 0 )); then
        echo "[ERROR] No split task files matching: tasks_${task_index}*.txt"; exit 2
    fi
else
    task_files=("tasks_${task_index}.txt")
    [[ -f "${task_files[0]}" ]] || { echo "[ERROR] Task file not found: ${task_files[0]}"; exit 2; }
fi

task_lines=()
task_line_sources=()
for tf in "${task_files[@]}"; do
    while IFS= read -r line || [[ -n "$line" ]]; do
        task_lines+=("$line")
        task_line_sources+=("$tf")
    done < "$tf"
done

# frozen_root: per-cluster convention.
case "$CANDEL_CLUSTER" in
    glamdring) frozen_root="/mnt/users/${USER}/frozen_candel" ;;
    arc)       frozen_root="/home/${USER}/frozen_candel" ;;
    *) echo "[ERROR] unknown cluster: $CANDEL_CLUSTER"; exit 1 ;;
esac

echo "Task submission ($CANDEL_CLUSTER)"
echo "============================================================"
if $local_mode; then
    echo "  Mode:        LOCAL (login node)"
else
    echo "  Mode:        SUBMIT (queue=$queue)"
fi
echo "  CPUs:        $ncpu"
echo "  Memory:      ${memory} GB"
$is_gpu && echo "  GPU:         yes${gputype:+ ($gputype)}"
echo "  Total tasks: ${#task_lines[@]}"
echo "  Frozen root: $frozen_root"
echo

echo "Tasks to run:"
for i in "${!task_lines[@]}"; do
    line="${task_lines[$i]}"
    idx=$(echo "$line" | cut -d' ' -f1)
    config_path=$(echo "$line" | cut -d' ' -f2-)
    echo "  - [${task_line_sources[$i]}] Task $idx: $config_path"
done
echo

read -rp "Proceed? [y/N]: " confirm
if [[ ! "$confirm" =~ ^[Yy]$ ]]; then echo "Aborting."; exit 1; fi

if [[ ! -d "$frozen_root" ]]; then
    echo "[ERROR] Frozen package not found: $frozen_root"
    echo "Run freeze_candel.sh first."; exit 4
fi

export PYTHONPATH="$frozen_root:${PYTHONPATH:-}"

for i in "${!task_lines[@]}"; do
    line="${task_lines[$i]}"
    idx=$(echo "$line" | cut -d' ' -f1)
    config_path=$(echo "$line" | cut -d' ' -f2-)

    echo "[INFO] === Task $idx (${task_line_sources[$i]}) ==="
    echo "[INFO] Config: $config_path"
    if [[ ! -f "$config_path" ]]; then
        echo "[WARNING] Config file not found: $config_path"; continue
    fi

    pycmd="$CANDEL_PYTHON $frozen_root/main.py --config $config_path --host-devices $ncpu"

    if $local_mode; then
        echo "[INFO] Running locally..."; echo "  $pycmd"
        eval "$pycmd"
    else
        gpu_flags=()
        if $is_gpu; then
            gpu_flags+=(--gpu)
            [[ -n "$gputype" ]] && gpu_flags+=(--gputype "$gputype")
            [[ -n "$gpu_mem" ]] && gpu_flags+=(--gpu-mem "$gpu_mem")
        fi
        dry_flag=()
        $dry && dry_flag=(--dry)
        submit_job "${gpu_flags[@]}" --queue "$queue" --mem "$memory" \
            --cpus "$ncpu" --name "task_${idx}" \
            --logdir "$ROOT/scripts/runs/logs" \
            "${dry_flag[@]}" -- $pycmd
    fi
    echo
done

echo "Done."
